<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('orders.view');$pdo=obtenerConexion();$qtxt=trim((string)($_GET['q']??''));$estado=trim((string)($_GET['estado']??''));$ambiente=trim((string)($_GET['ambiente']??''));$pagina=max(1,(int)($_GET['pagina']??1));$lim=25;$from=' FROM dte_documentos d JOIN pedidos p ON p.id=d.pedido_id JOIN usuarios u ON u.id=p.usuario_id';$where=' WHERE 1';$pa=[];if($qtxt!==''){$where.=' AND (d.codigo_generacion LIKE :q OR d.numero_control LIKE :q OR p.numero LIKE :q OR u.correo LIKE :q)';$pa['q']='%'.$qtxt.'%';}if($estado!==''){$where.=' AND d.estado=:e';$pa['e']=mb_substr($estado,0,40);}if(in_array($ambiente,['simulation','test','production'],true)){$where.=' AND d.ambiente=:a';$pa['a']=$ambiente;}$q=$pdo->prepare('SELECT COUNT(*)'.$from.$where);$q->execute($pa);$total=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT d.*,p.numero,p.total,u.nombre,u.apellido,u.correo'.$from.$where.' ORDER BY d.emitido_at DESC,d.id DESC LIMIT :lim OFFSET :off');foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$lim,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$lim,PDO::PARAM_INT);$q->execute();$docs=$q->fetchAll();cmsCabecera('Facturas / DTE','facturas/index.php','Documentos emitidos, descargas y eventos del proveedor.');?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><div class="col-md-5"><input class="form-control" name="q" value="<?=atenea_e($qtxt)?>" placeholder="Código, control, pedido o cliente"></div><div class="col-md-2"><input class="form-control" name="estado" value="<?=atenea_e($estado)?>" placeholder="Estado"></div><div class="col-md-3"><select class="form-select" name="ambiente"><option value="">Todos los ambientes</option><?php foreach(['simulation','test','production'] as$a):?><option <?=$ambiente===$a?'selected':''?>><?=$a?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><div class="table-responsive"><table class="table"><thead><tr><th>Documento</th><th>Pedido / cliente</th><th>Ambiente</th><th>Estado</th><th>Total</th><th>Fecha</th><th></th></tr></thead><tbody><?php foreach($docs as$d):?><tr><td><small><?=atenea_e($d['codigo_generacion'])?></small><small class="d-block"><?=atenea_e($d['numero_control'])?></small></td><td><?=atenea_e($d['numero'])?><small class="d-block"><?=atenea_e(trim($d['nombre'].' '.$d['apellido']))?></small></td><td><?=atenea_e($d['ambiente'])?></td><td><?=atenea_e($d['estado'])?></td><td>$<?=number_format((float)$d['total'],2)?></td><td><?=date('d/m/Y H:i',strtotime($d['emitido_at']))?></td><td><a class="btn btn-sm btn-outline-primary" href="detalle.php?id=<?=$d['id']?>">Ver</a></td></tr><?php endforeach;?><?php if(!$docs):?><tr><td colspan="7" class="text-center py-5">No hay DTE para estos filtros.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
